import{_ as t,o,c as d,a4 as a}from"./chunks/framework.4M7SpZrd.js";const g=JSON.parse('{"title":"Activity & Audit Logs","description":"","frontmatter":{},"headers":[],"relativePath":"admin/activity-audit-logs.md","filePath":"admin/activity-audit-logs.md"}'),i={name:"admin/activity-audit-logs.md"};function c(s,e,r,n,l,m){return o(),d("div",null,[...e[0]||(e[0]=[a(`<h1 id="activity-audit-logs" tabindex="-1">Activity &amp; Audit Logs <a class="header-anchor" href="#activity-audit-logs" aria-label="Permalink to &quot;Activity &amp; Audit Logs&quot;">​</a></h1><h2 id="activity-logs-dos-motores" tabindex="-1">Activity Logs dos Motores <a class="header-anchor" href="#activity-logs-dos-motores" aria-label="Permalink to &quot;Activity Logs dos Motores&quot;">​</a></h2><blockquote><p><strong>Admin page:</strong> <code>/activity-logs</code><strong>Arquivo:</strong> <code>app/api/v1/admin/activity_logs_admin.py</code></p></blockquote><p>Os Activity Logs registram toda a atividade dos motores de busca em tempo real. Cada execucao gera um <code>trace_id</code> unico que conecta os logs da API e do Celery, permitindo rastrear o fluxo completo de uma operacao.</p><h3 id="endpoints" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints" aria-label="Permalink to &quot;Endpoints&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metodo</th><th>Rota</th><th>Descricao</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/activity-logs</code></td><td>Lista paginada com filtros (<code>motor_id</code>, <code>level</code>, <code>trace_id</code>, <code>task_id</code>, <code>search</code>, date range)</td></tr><tr><td><code>GET</code></td><td><code>/admin/activity-logs/stream</code></td><td>SSE (Server-Sent Events) em tempo real via Redis Pub/Sub (<code>ACTIVITY_CHANNEL</code>)</td></tr><tr><td><code>GET</code></td><td><code>/admin/activity-logs/traces/{trace_id}</code></td><td>Timeline completa de uma execucao</td></tr><tr><td><code>GET</code></td><td><code>/admin/activity-logs/stats</code></td><td>Resumo das ultimas 24h por level e motor</td></tr></tbody></table><h3 id="schema-engineactivitylog" tabindex="-1">Schema: EngineActivityLog <a class="header-anchor" href="#schema-engineactivitylog" aria-label="Permalink to &quot;Schema: EngineActivityLog&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Campo</th><th>Tipo</th><th>Descricao</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>int</code></td><td>PK</td></tr><tr><td><code>trace_id</code></td><td><code>varchar</code></td><td>UUID propagado entre API e Celery</td></tr><tr><td><code>motor_id</code></td><td><code>int</code></td><td>Motor que gerou o log</td></tr><tr><td><code>motor_name</code></td><td><code>varchar</code></td><td>Nome legivel do motor</td></tr><tr><td><code>level</code></td><td><code>varchar</code></td><td><code>info</code> / <code>warning</code> / <code>error</code></td></tr><tr><td><code>message</code></td><td><code>text</code></td><td>Mensagem principal</td></tr><tr><td><code>details</code></td><td><code>JSONB</code></td><td>Dados adicionais (estrutura livre)</td></tr><tr><td><code>task_id</code></td><td><code>varchar</code></td><td>Celery task ID</td></tr><tr><td><code>created_at</code></td><td><code>timestamp</code></td><td>Data/hora do registro</td></tr></tbody></table><h3 id="sse-streaming" tabindex="-1">SSE Streaming <a class="header-anchor" href="#sse-streaming" aria-label="Permalink to &quot;SSE Streaming&quot;">​</a></h3><p>O endpoint <code>/stream</code> permite que o frontend receba logs em tempo real sem polling.</p><ul><li>Retorna <code>StreamingResponse</code> com <code>content-type: text/event-stream</code></li><li>Dados publicados via <strong>Redis Pub/Sub</strong> no canal <code>ACTIVITY_CHANNEL</code></li><li>Frontend consome via <code>EventSource</code> API nativa do browser</li><li><strong>Nginx prod:</strong> <code>proxy_buffering off</code> e <code>timeout 3600s</code> configurados para este endpoint</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────┐    Pub/Sub     ┌──────────┐     SSE      ┌──────────┐</span></span>
<span class="line"><span>│  Celery  │ ──────────────&gt;│  Redis   │ ────────────&gt;│ Frontend │</span></span>
<span class="line"><span>│  Worker  │  ACTIVITY_CH   │  Server  │  /stream     │  Admin   │</span></span>
<span class="line"><span>└──────────┘                └──────────┘              └──────────┘</span></span></code></pre></div><hr><h2 id="audit-logs" tabindex="-1">Audit Logs <a class="header-anchor" href="#audit-logs" aria-label="Permalink to &quot;Audit Logs&quot;">​</a></h2><blockquote><p><strong>Admin page:</strong> <code>/audit-logs</code><strong>Arquivo:</strong> <code>app/api/v1/admin/audit_logs.py</code></p></blockquote><p>Os Audit Logs registram todas as acoes sensiveis do sistema para fins de seguranca e conformidade com a LGPD.</p><h3 id="endpoints-1" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints-1" aria-label="Permalink to &quot;Endpoints&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Metodo</th><th>Rota</th><th>Descricao</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/admin/audit-logs</code></td><td>Lista paginada com filtros (<code>action</code>, <code>user_id</code>, <code>ip</code>, <code>date_from</code>, <code>date_to</code>). LEFT JOIN com User para mostrar email. Window function para total count (single query).</td></tr><tr><td><code>GET</code></td><td><code>/admin/audit-logs/export/csv</code></td><td>Exportacao CSV com <code>StreamingResponse</code></td></tr></tbody></table><h3 id="acoes-registradas" tabindex="-1">Acoes registradas <a class="header-anchor" href="#acoes-registradas" aria-label="Permalink to &quot;Acoes registradas&quot;">​</a></h3><p>As seguintes acoes sao capturadas automaticamente no audit log:</p><ul><li><code>login</code> — Login de usuario</li><li><code>register</code> — Registro de nova conta</li><li><code>logout</code> — Logout</li><li><code>setup_2fa</code> — Ativacao de autenticacao em dois fatores</li><li><code>disable_2fa</code> — Desativacao de 2FA</li><li><code>change_password</code> — Alteracao de senha</li><li><code>delete_account</code> — Exclusao de conta</li><li><code>approve_identity</code> — Aprovacao de identidade (admin)</li><li><code>reject_identity</code> — Rejeicao de identidade (admin)</li><li><code>revoke_embedding</code> — Revogacao de embedding facial</li><li>Demais operacoes administrativas</li></ul><h3 id="lgpd" tabindex="-1">LGPD <a class="header-anchor" href="#lgpd" aria-label="Permalink to &quot;LGPD&quot;">​</a></h3><p>Os audit logs sao preservados de forma <strong>anonimizada</strong> quando um usuario exclui sua conta. O relacionamento com a tabela User utiliza <code>ondelete=SET NULL</code>, garantindo que os registros de auditoria permanecem no sistema sem dados pessoais identificaveis, em conformidade com a Lei Geral de Protecao de Dados.</p>`,23)])])}const u=t(i,[["render",c]]);export{g as __pageData,u as default};
